    desc = row['Patient_description']
    hist_type = row['histological_type']

    if not hist_type or hist_type.startswith('['):
        continue

    match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
    if not match:
        continue

    barcode = match.group()

    if hist_type not in histology_counts:
        histology_counts[hist_type] = {'total': 0, 'mutated': 0}

    histology_counts[hist_type]['total'] += 1
    if barcode in mutated_barcodes:
        histology_counts[hist_type]['mutated'] += 1

# Filter out categories with marginal totals <= 10
filtered_histology = {k: v for k, v in histology_counts.items() if v['total'] > 10}

grand_total = sum(v['total'] for v in filtered_histology.values())
total_mutated = sum(v['mutated'] for v in filtered_histology.values())
total_not_mutated = grand_total - total_mutated

chi2 = 0.0
for hist_type, counts in filtered_histology.items():
    row_total = counts['total']

    # Mutated cell
    obs_mut = counts['mutated']
    exp_mut = (row_total * total_mutated) / grand_total
    if exp_mut > 0:
        chi2 += ((obs_mut - exp_mut) ** 2) / exp_mut

    # Not mutated cell
    obs_not_mut = row_total - obs_mut
    exp_not_mut = (row_total * total_not_mut) / grand_total
    if exp_not_mut > 0:
        chi2 += ((obs_not_mut - exp_not_mut) ** 2) / exp_not_mut

print(f"Chi-square: {chi2}")
env['_answer'] = chi2
